import{_ as e}from"./chunks/quickstart_01.CAs9iatn.js";import{_ as a,o as r,c as s,a2 as i}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"빠른 시작","description":"","frontmatter":{},"headers":[],"relativePath":"ko/getting-started/quickstart.md","filePath":"ko/getting-started/quickstart.md"}'),o={name:"ko/getting-started/quickstart.md"};function l(c,t,n,d,p,g){return r(),s("div",null,[...t[0]||(t[0]=[i('<h1 id="빠른-시작" tabindex="-1"><i class="ph ph-target"></i> 빠른 시작 <a class="header-anchor" href="#빠른-시작" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-target&quot;&gt;&lt;/i&gt; 빠른 시작&quot;">​</a></h1><p>WebAP 플러그인은 <em>플러그 앤 플레이</em> 방식으로 설계되었습니다. 코드를 작성하거나 시작 씬에 관리자를 추가할 필요가 없습니다 — 시스템은 자동으로 초기화됩니다.</p><h2 id="_1-플러그인-활성화" tabindex="-1">1. 플러그인 활성화 <a class="header-anchor" href="#_1-플러그인-활성화" aria-label="Permalink to &quot;1. 플러그인 활성화&quot;">​</a></h2><ol><li><strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong> 로 이동합니다.</li><li><strong>Enable Web Adaptive Performance</strong> 체크박스를 활성화합니다.</li><li>Scalers 탭을 확장하고 게임의 특성에 가장 잘 맞는 추가 모듈을 활성화합니다(예: 물리 단계 또는 그림자 품질) (자세한 내용은 <a href="./../scalers/reference">Scaler 레퍼런스</a> 참조).</li></ol><p><img src="'+e+'" alt=""></p><div class="info custom-block"><p class="custom-block-title">기본 설정</p><p>기본 설정은 대부분의 프로젝트에서 최적의 성능을 제공하도록 사전 구성되어 있습니다. 설정을 그대로 유지하세요.</p></div><h2 id="_2-플레이어-설정-player-settings-구성" tabindex="-1">2. 플레이어 설정(Player Settings) 구성 <a class="header-anchor" href="#_2-플레이어-설정-player-settings-구성" aria-label="Permalink to &quot;2. 플레이어 설정(Player Settings) 구성&quot;">​</a></h2><p>플러그인의 Tracker가 수학적으로 프로세서(CPU) 랙과 비디오 카드(GPU) 랙을 구별하려면 하드웨어의 정확한 프레임 타이밍에 접근해야 합니다.</p><div class="warning custom-block"><p class="custom-block-title">프레임 타이밍 통계 (Frame Timing Stats)</p><p><strong>Edit -&gt; Project Settings -&gt; Player -&gt; Other Settings -&gt; Rendering</strong> 으로 이동하여 <strong>Frame Timing Stats</strong> 를 체크하세요. 이 설정이 없으면 병목 현상(Bottleneck) 감지가 작동하지 않습니다.</p></div><h2 id="_3-그래픽-설정" tabindex="-1">3. 그래픽 설정 <a class="header-anchor" href="#_3-그래픽-설정" aria-label="Permalink to &quot;3. 그래픽 설정&quot;">​</a></h2><p>다양한 디바이스를 위해 별도의 품질 프리셋(Low, Medium, High)을 만들어 플레이어가 수동으로 선택하도록 강요하는 것을 멈추세요.</p><div class="tip custom-block"><p class="custom-block-title">그래픽 품질 최대화</p><p>프로젝트를 최대 품질로 설정하세요. BiRP의 경우 <code>Project Settings -&gt; Quality</code>에서 설정하고, URP의 경우 <code>URP Asset</code> 내부에서 설정하세요. 플레이어의 디바이스에 성능 여유(Performance Headroom)가 부족한 경우 플러그인이 런타임 중에 활성화한 Scaler만 사용하여 부드럽게 부하를 자동으로 줄여줍니다.</p></div>',12)])])}const u=a(o,[["render",l]]);export{h as __pageData,u as default};
